const item = $input.first().json;

// Support both query param and path-style execution_id
const executionId = item.query?.execution_id || item.body?.execution_id || item.headers?.['x-execution-id'];

if (!executionId) {
  return [{
    json: {
      success: false,
      error: 'Missing execution_id. Provide via query parameter: ?execution_id=exec_...'
    }
  }];
}

// Read from the master orchestrator workflow's static data
// Note: n8n static data is per-workflow, so this workflow needs
// its own tracking or the orchestrator must write to a shared store.
// For simplicity, we use a shared global static data approach.
const workflowStaticData = getWorkflowStaticData('global');
const state = workflowStaticData[executionId];

if (!state) {
  return [{
    json: {
      success: false,
      error: 'Execution not found',
      execution_id: executionId
    }
  }];
}

return [{
  json: {
    success: true,
    execution_id: executionId,
    status: state.status,
    progress: state.progress,
    current_step: state.current_step,
    steps_completed: state.steps_completed,
    started_at: state.started_at,
    completed_at: state.completed_at || null,
    final_video_url: state.final_video_url || null,
    errors: state.errors
  }
}];
